package mhir.parse

import mhir.canonicalize._
import mhir.ir._
import mhir.sugar._

import scala.annotation.tailrec
import scala.collection.immutable.ListMap

/** Parser for [[https://dl.acm.org/doi/10.1145/3385412.3385983 Aetherling]]'s
  * space-time language.
  */
object AetherlingParser {

  /** Parse a program from Aetherling's space-time language to an
    * [[mhir.ir.Expr]].
    *
    * ==Grammar==
    * The program must be generated by the following grammar:
    * {{{
    *   prog       ::= module+
    *   module     ::= ident (" " | param+) " =" assignment+ "\n\n"
    *   param      ::= " (" ident " :: " typ ")"
    *   typ        ::= "UnitT"
    *                | "BitT"
    *                | "Int8T"
    *                | "UInt8T"
    *                | "FixP1_7T"
    *                | "Int16T"
    *                | "UInt16T"
    *                | "Int32T"
    *                | "UInt32T"
    *                | "(ATupleT " typ " " typ ")"
    *                | "(STupleT " nat " " typ ")"
    *                | "(SSeqT " nat " " typ ")"
    *                | "(TSeqT " nat " " nat " " typ ")"
    *   assignment ::= "\n    " ident " = " expr
    *   expr       ::= "(" expr ")"
    *                | ident
    *                | quot_ident
    *                // ----- basic operators
    *                | "IdN " expr
    *                | "AbsN " typ " " expr
    *                | "NotN " expr
    *                | "AndN " expr
    *                | "OrN " expr
    *                | "AddN " typ " " expr
    *                | "SubN " typ " " expr
    *                | "MulN " typ " " expr
    *                | "DivN " typ " " expr
    *                | "LSRN " typ " " expr
    *                | "LSLN " typ " " expr
    *                | "LtN " typ " " expr
    *                | "EqN " typ " " expr
    *                | "IfN " typ " " expr
    *                // ----- generators
    *                | "Lut_GenN " const_list " " typ " " expr
    *                | "Const_GenN " const " " nat " " typ
    *                | "Counter_sN " nat " " nat " " typ " " nat
    *                | "Counter_tN " nat " " nat " " nat " " typ " " nat
    *                | "Counter_tsN " nat " " nat " " nat " " nat " " typ " " nat
    *                | "Counter_tnN " nat_list " " nat_list " " nat " " typ " " nat
    *                // ----- sequence operators
    *                | "Shift_sN " nat " " nat " " typ " " expr
    *                | "Shift_tN " nat " " nat " " nat " " typ " " expr
    *                | "Shift_tsN " nat " " nat " " nat " " nat " " typ " " expr
    *                | "Shift_ttN " nat " " nat " " nat " " nat " " nat " " typ " " expr
    *                | "Shift_tnN " nat " " nat_list " " nat " " nat_list " " nat " " typ " " expr
    *                | "Up_1d_sN " nat " " typ " " expr
    *                | "Up_1d_tN " nat " " nat " " typ " " expr
    *                | "Down_1d_sN " nat " " nat " " typ " " expr
    *                | "Down_1d_tN " nat " " nat " " nat " " typ " " expr
    *                | "Partition_s_ssN " nat " " nat " " typ " " expr
    *                | "Partition_t_ttN " nat " " nat " " nat " " nat " " typ " " expr
    *                | "Unpartition_s_ssN " nat " " nat " " typ " " expr
    *                | "Unpartition_t_ttN " nat " " nat " " nat " " nat " " typ " " expr
    *                | "SerializeN " nat " " nat " " typ " " expr
    *                | "DeserializeN " nat " " nat " " typ " " expr
    *                | "Add_1_sN " expr " " expr
    *                | "Add_1_0_tN " expr " " expr
    *                | "Remove_1_sN " expr " " expr
    *                | "Remove_1_0_tN " expr " " expr
    *                // ----- higher-order operators
    *                | "Map_sN " nat " " expr " " expr
    *                | "Map_tN " nat " " nat " " expr " " expr
    *                | "Map2_sN " nat " " expr " " expr " " expr
    *                | "Map2_tN " nat " " nat " " expr " " expr " " expr
    *                | "Reduce_sN " nat " " expr " " expr
    *                | "Reduce_tN " nat " " nat " " expr " " expr
    *                // ----- tuple operators
    *                | "FstN " typ " " typ " " expr
    *                | "SndN " typ " " typ " " expr
    *                | "ATupleN " typ " " typ " " expr " " expr
    *                | "STupleN " typ " " expr " " expr
    *                | "STupleAppendN " nat " " typ " " expr " " expr
    *                | "STupleToSSeqN " nat " " typ " " expr
    *                | "SSeqToSTupleN " nat " " typ " " expr
    *                // ----- miscellaneous
    *                | "FIFON " typ " " nat " " expr
    *                | "ReshapeN (" typ ") (" typ ") " expr
    *   const      ::= "UnitV"
    *                | "BitV " bool
    *                | "Int8V " int
    *                | "UInt8V " nat
    *                | "FixP1_7V " float
    *                | "Int16V " int
    *                | "UInt16V " nat
    *                | "Int32V " int
    *                | "UInt32V " nat
    *                | "ATupleV (" const ") (" const ")"
    *                | "STupleV " const_list
    *                | "SSeqV " const_list
    *                | "TSeqV {vals = " const_list ", i_v = " nat "}"
    *   const_list ::= "[]"
    *                | "[" const ("," const)* "]"
    *   ident      ::= letter (letter | digit)*
    *   quot_ident ::= "\"" ident "\""
    *   nat        ::= digit+
    *   nat_list   ::= "[]"
    *                | "[" nat ("," nat)* "]"
    *   int        ::= nat
    *                | "-" nat
    *                | "(" int ")"
    *   bool       ::= "True" | "False"
    * }}}
    *
    * @param code
    *   an Aetherling program.
    * @throws SyntaxError
    *   if the program is syntactically invalid.
    */
  def parse(code: String): Expr = {
    parseProgram(code, ListMap())
  }

  @tailrec
  private def parseProgram(
      code: String,
      modules: ListMap[Param, Function]
  ): Expr = {
    val (modName, modImpl, suffix) = parseModule(code, modules)
    if (suffix.isBlank) {
      Lets(modules.toSeq: _*)(modImpl)
    } else {
      parseProgram(suffix, modules + (modName -> modImpl))
    }
  }

  private def parseModule(
      code: String,
      modules: ListMap[Param, Function]
  ): (Param, Function, String) = {
    val (name, suffix0) = parseIdentifier(code)
    val (params, suffix1) = if (suffix0.startsWith(" (")) {
      parseOneOrMoreParams(suffix0, Seq())
    } else {
      (Seq(), expect(suffix0, " "))
    }
    val suffix2 = expect(suffix1, " =")
    val (assignments, suffix3) =
      parseOneOrMoreAssignments(suffix2, modules, ListMap())
    val suffix4 = expect(suffix3, "\n\n")
    val func = {
      val body = Lets(assignments.toSeq.init: _*)(assignments.last._2)
      if (params.isEmpty) {
        val x0 = Param("dummy")(TyTuple())
        Function(x0, body)()
      } else {
        val x0 = params.last
        val f0 = Function(x0, body)()
        params.init.foldRight(f0)({ case (x, body) => Function(x, body)() })
      }
    }
    (name, func, suffix4)
  }

  private def parseIdentifier(code: String): (Param, String) = {
    if (code.isEmpty || !code.head.isLetter) {
      throw SyntaxError(s"Expected an identifier but got $code")
    }
    val (name, suffix) = code.span(c => c.isLetterOrDigit)
    (Param(name, -1)(Missing), suffix)
  }

  private def parseQuotedIdentifier(code: String): (Param, String) = {
    val suffix0 = expect(code, "\"")
    val (x, suffix1) = parseIdentifier(suffix0)
    val suffix2 = expect(suffix1, "\"")
    (x, suffix2)
  }

  @tailrec
  private def parseOneOrMoreParams(
      code: String,
      params: Seq[Param]
  ): (Seq[Param], String) = {
    val (x, suffix) = parseParam(code)
    if (suffix.startsWith(" (")) {
      parseOneOrMoreParams(suffix, params :+ x)
    } else {
      (params :+ x, suffix)
    }
  }

  private def parseParam(code: String): (Param, String) = {
    val suffix0 = expect(code, " (")
    val (name, suffix1) = parseIdentifier(suffix0)
    val suffix2 = expect(suffix1, " :: ")
    val (typ, suffix3) = parseTyp(suffix2)
    val suffix4 = expect(suffix3, ")")
    (name.rebuild(typ).asInstanceOf[Param], suffix4)
  }

  @tailrec
  private def parseOneOrMoreAssignments(
      code: String,
      modules: ListMap[Param, Function],
      assignments: ListMap[Param, Expr]
  ): (ListMap[Param, Expr], String) = {
    val (x, v, suffix) = parseAssignment(code, modules)
    if (suffix.startsWith("\n    ")) {
      parseOneOrMoreAssignments(suffix, modules, assignments + (x -> v))
    } else {
      (assignments + (x -> v), suffix)
    }
  }

  private def parseAssignment(
      code: String,
      modules: ListMap[Param, Function]
  ): (Param, Expr, String) = {
    val suffix0 = expect(code, "\n    ")
    val (x, suffix1) = parseIdentifier(suffix0)
    val suffix2 = expect(suffix1, " = ")
    val (v, suffix3) = parseExpr(suffix2, modules)
    (x, v, suffix3)
  }

  private def parseTyp(code: String): (Type, String) = {
    if (code.startsWith("UnitT")) {
      (TyTuple(), expect(code, "UnitT"))
    } else if (code.startsWith("BitT")) {
      (TyBool, expect(code, "BitT"))
    } else if (code.startsWith("Int8T")) {
      (I8, expect(code, "Int8T"))
    } else if (code.startsWith("UInt8T")) {
      (U8, expect(code, "UInt8T"))
    } else if (code.startsWith("FixP1_7T")) {
      (TyFix(U8, 7), expect(code, "FixP1_7T"))
    } else if (code.startsWith("Int16T")) {
      (I16, expect(code, "Int16T"))
    } else if (code.startsWith("UInt16T")) {
      (U16, expect(code, "UInt16T"))
    } else if (code.startsWith("Int32T")) {
      (I32, expect(code, "Int32T"))
    } else if (code.startsWith("UInt32T")) {
      (U32, expect(code, "UInt32T"))
    } else if (code.startsWith("(ATupleT ")) {
      val suffix0 = expect(code, "(ATupleT ")
      val (t0, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (t1, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, ")")
      (TyTuple(t0, t1), suffix4)
    } else if (code.startsWith("(STupleT ")) {
      val suffix0 = expect(code, "(STupleT ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (t, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, ")")
      (TyVec(t, n), suffix4)
    } else if (code.startsWith("(SSeqT ")) {
      val suffix0 = expect(code, "(SSeqT ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (t, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, ")")
      (TyVec(t, n), suffix4)
    } else if (code.startsWith("(TSeqT ")) {
      val suffix0 = expect(code, "(TSeqT ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (t, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, ")")
      (TyStm(t, n), suffix6)
    } else {
      throw SyntaxError(s"Expected a type but got $code")
    }
  }

  private def parseNat(code: String): (Int, String) = {
    if (code.nonEmpty && code.head.isDigit) {
      val (nStr, suffix) = code.span(c => c.isDigit)
      assert(nStr.nonEmpty)
      val n = Integer.parseUnsignedInt(nStr)
      (n, suffix)
    } else {
      throw SyntaxError(s"Expected a natural number but got $code")
    }
  }

  private def parseNatList(code: String): (Seq[Int], String) = {
    if (code.startsWith("[]")) {
      (Seq(), expect(code, "[]"))
    } else {
      val suffix0 = expect(code, "[")
      val (elems, suffix1) = parseOneOrMoreNat(suffix0, Seq())
      val suffix2 = expect(suffix1, "]")
      (elems, suffix2)
    }
  }

  @tailrec
  private def parseOneOrMoreNat(
      code: String,
      elems: Seq[Int]
  ): (Seq[Int], String) = {
    val (elem0, suffix0) = parseNat(code)
    if (suffix0.startsWith(",")) {
      val suffix1 = expect(suffix0, ",")
      parseOneOrMoreNat(suffix1, elems :+ elem0)
    } else {
      (elems :+ elem0, suffix0)
    }
  }

  private def parseInt(code: String): (Int, String) = {
    if (code.startsWith("(")) {
      val suffix0 = expect(code, "(")
      val (n, suffix1) = parseInt(suffix0)
      val suffix2 = expect(suffix1, ")")
      (n, suffix2)
    } else if (code.startsWith("-")) {
      val suffix0 = expect(code, "-")
      val (n, suffix1) = parseNat(suffix0)
      (-n, suffix1)
    } else {
      parseNat(code)
    }
  }

  private def parseFloat(code: String): (Float, String) = {
    val (prefix, suffix) = code.span({
      case c if c.isDigit  => true
      case '.' | 'e' | '-' => true
      case _               => false
    })
    (prefix.toFloat, suffix)
  }

  private def parseExpr(
      code: String,
      modules: ListMap[Param, Function]
  ): (Expr, String) = {
    if (code.startsWith("(")) {
      val suffix0 = expect(code, "(")
      val (e, suffix1) = parseExpr(suffix0, modules)
      val suffix2 = expect(suffix1, ")")
      (e, suffix2)
    } else if (code.startsWith("IdN ")) {
      val suffix0 = expect(code, "IdN ")
      val (e, suffix1) = parseExpr(suffix0, modules)
      (e, suffix1)
    } else if (code.startsWith("AbsN ")) {
      val suffix0 = expect(code, "AbsN ")
      val (typ, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      val abs = typ.asInstanceOf[TyAnyInt] match {
        case _: TySInt => Mux(e < 0, C(-1)() * e, e)()
        case _: TyUInt => e
      }
      (abs, suffix3)
    } else if (code.startsWith("NotN ")) {
      val suffix0 = expect(code, "NotN ")
      val (e, suffix1) = parseExpr(suffix0, modules)
      (Not(e)(), suffix1)
    } else if (code.startsWith("AndN ")) {
      val suffix0 = expect(code, "AndN ")
      val (e, suffix1) = parseExpr(suffix0, modules)
      (e.__0 && e.__1, suffix1)
    } else if (code.startsWith("OrN ")) {
      val suffix0 = expect(code, "OrN ")
      val (e, suffix1) = parseExpr(suffix0, modules)
      (e.__0 || e.__1, suffix1)
    } else if (code.startsWith("AddN ")) {
      val suffix0 = expect(code, "AddN ")
      // TODO: Add a node like `AssertType` which is removed by the type
      //       checker?
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (WrappingSum(e.__0, e.__1)(), suffix3)
    } else if (code.startsWith("SubN ")) {
      val suffix0 = expect(code, "SubN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (WrappingDiff(e.__0, e.__1)(), suffix3)
    } else if (code.startsWith("MulN ")) {
      val suffix0 = expect(code, "MulN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (WrappingProd(e.__0, e.__1)(), suffix3)
    } else if (code.startsWith("DivN ")) {
      val suffix0 = expect(code, "DivN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (IntFixProd(e.__0, e.__1)(), suffix3)
    } else if (code.startsWith("LSRN ")) {
      val suffix0 = expect(code, "LSRN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (e.__0 >>> e.__1, suffix3)
    } else if (code.startsWith("LSLN ")) {
      val suffix0 = expect(code, "LSLN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (e.__0 <<< e.__1, suffix3)
    } else if (code.startsWith("LtN ")) {
      val suffix0 = expect(code, "LtN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (e.__0 < e.__1, suffix3)
    } else if (code.startsWith("EqN ")) {
      val suffix0 = expect(code, "EqN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (SmartEqual(e.__0, e.__1)(), suffix3)
    } else if (code.startsWith("IfN ")) {
      val suffix0 = expect(code, "IfN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (Mux(e.__0, e.__1.__0, e.__1.__1)(), suffix3)
    } else if (code.startsWith("Lut_GenN ")) {
      val suffix0 = expect(code, "Lut_GenN ")
      val (elems, suffix1) = parseConstList(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (idx, suffix5) = parseExpr(suffix4, modules)
      (VecAccess(VecLiteral(elems: _*)(), idx)(), suffix5)
    } else if (code.startsWith("Const_GenN ")) {
      val suffix0 = expect(code, "Const_GenN ")
      val (c, suffix1) = parseConst(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      (c, suffix5)
    } else if (code.startsWith("Counter_sN ")) {
      val suffix0 = expect(code, "Counter_sN ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (delta, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (typ, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (_, suffix7) = parseNat(suffix6)
      val idxTyp = TyAnyInt.tightest(0, n - 1)
      (VecBuild(n, idxTyp ::+ (i => ReshapeData(i * delta, typ)()))(), suffix7)
    } else if (code.startsWith("Counter_tN ")) {
      val suffix0 = expect(code, "Counter_tN ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (delta, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (typ, suffix7) = parseTyp(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (_, suffix9) = parseNat(suffix8)
      (StmRange(n, C(0)(typ), C(delta)(typ))(), suffix9)
    } else if (code.startsWith("Counter_tsN ")) {
      val suffix0 = expect(code, "Counter_tsN ")
      val (no, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (ni, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (delta, suffix7) = parseNat(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (typ, suffix9) = parseTyp(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (_, suffix11) = parseNat(suffix10)
      (StmVecRange(no, ni, C(0)(typ), C(delta)(typ))(), suffix11)
    } else if (code.startsWith("Counter_tnN ")) {
      val suffix0 = expect(code, "Counter_tnN ")
      val (ns, suffix1) = parseNatList(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (is, suffix3) = parseNatList(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (delta, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (typ, suffix7) = parseTyp(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (_, suffix9) = parseNat(suffix8)
      (makeNestedStmCounter(1, ns, is, delta, typ), suffix9)
    } else if (code.startsWith("Shift_sN ")) {
      val suffix0 = expect(code, "Shift_sN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (shiftAmount, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (v, suffix7) = parseExpr(suffix6, modules)
      (VecShiftRightGarbage(v, shiftAmount)(), suffix7)
    } else if (code.startsWith("Shift_tN ")) {
      val suffix0 = expect(code, "Shift_tN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (shiftAmount, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (_, suffix7) = parseTyp(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (s, suffix9) = parseExpr(suffix8, modules)
      (StmShiftRightGarbage(s, shiftAmount)(), suffix9)
    } else if (code.startsWith("Shift_tsN ")) {
      // Shift_tsN seems to have type
      //     TSeq no io (SSeq ni t) -> TSeq no io (SSeq ni t)
      // Or, in the notation of this IR:
      //     Stm[Vec[t, ni], no] -> Stm[Vec[t, ni], no]
      val suffix0 = expect(code, "Shift_tsN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (shiftAmount, suffix7) = parseNat(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (_, suffix9) = parseTyp(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (s, suffix11) = parseExpr(suffix10, modules)
      (StmVecShiftRightGarbage(s, shiftAmount)(), suffix11)
    } else if (code.startsWith("Shift_ttN ")) {
      val suffix0 = expect(code, "Shift_ttN")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (ni, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (ii, suffix7) = parseNat(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (shiftAmount, suffix9) = parseNat(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (_, suffix11) = parseTyp(suffix10)
      val suffix12 = expect(suffix11, " ")
      val (s, suffix13) = parseExpr(suffix12, modules)
      (makeNestedStmShift(s, Seq(ni), Seq(ii), shiftAmount), suffix13)
    } else if (code.startsWith("Shift_tnN ")) {
      // This seems to me like just a generalization of shift_tt to handle an
      // arbitrary amount of nesting
      val suffix0 = expect(code, "Shift_tnN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (nis, suffix3) = parseNatList(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (iis, suffix7) = parseNatList(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (shiftAmount, suffix9) = parseNat(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (_, suffix11) = parseTyp(suffix10)
      val suffix12 = expect(suffix11, " ")
      val (s, suffix13) = parseExpr(suffix12, modules)
      (makeNestedStmShift(s, nis, iis, shiftAmount), suffix13)
    } else if (code.startsWith("Up_1d_sN")) {
      val suffix0 = expect(code, "Up_1d_sN ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (v, suffix5) = parseExpr(suffix4, modules)
      (VecBuild(n, U32 ::+ (_ => VecAccess(v, 0)()))(), suffix5)
    } else if (code.startsWith("Up_1d_tN ")) {
      val suffix0 = expect(code, "Up_1d_tN ")
      val (n, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (s, suffix7) = parseExpr(suffix6, modules)
      (StmJoin(StmRepeat(s, n)())(), suffix7)
    } else if (code.startsWith("Down_1d_sN ")) {
      val suffix0 = expect(code, "Down_1d_sN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (idx, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (v, suffix7) = parseExpr(suffix6, modules)
      (VecBuild(1, U8 ::+ (_ => VecAccess(v, idx)()))(), suffix7)
    } else if (code.startsWith("Down_1d_tN ")) {
      val suffix0 = expect(code, "Down_1d_tN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (idx, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (_, suffix7) = parseTyp(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (s, suffix9) = parseExpr(suffix8, modules)
      (StmAccess(s, idx)(), suffix9)
    } else if (code.startsWith("Partition_s_ssN ")) {
      val suffix0 = expect(code, "Partition_s_ssN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (ni, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (v, suffix7) = parseExpr(suffix6, modules)
      (VecSplit(v, ni)(), suffix7)
    } else if (code.startsWith("Partition_t_ttN ")) {
      val suffix0 = expect(code, "Partition_t_ttN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (ni, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (_, suffix7) = parseNat(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (_, suffix9) = parseTyp(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (s, suffix11) = parseExpr(suffix10, modules)
      (StmSplit(s, ni)(), suffix11)
    } else if (code.startsWith("Unpartition_s_ssN ")) {
      val suffix0 = expect(code, "Unpartition_s_ssN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (v, suffix7) = parseExpr(suffix6, modules)
      (VecJoin(v)(), suffix7)
    } else if (code.startsWith("Unpartition_t_ttN ")) {
      val suffix0 = expect(code, "Unpartition_t_ttN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseNat(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (_, suffix7) = parseNat(suffix6)
      val suffix8 = expect(suffix7, " ")
      val (_, suffix9) = parseTyp(suffix8)
      val suffix10 = expect(suffix9, " ")
      val (s, suffix11) = parseExpr(suffix10, modules)
      (StmJoin(s)(), suffix11)
    } else if (code.startsWith("SerializeN ")) {
      // SerializeN seems to have type
      //     TSeq 1 (n + i - 1) (STuple n t) -> TSeq n i t
      // Or, in the notation of this IR:
      //     Stm[Vec[t, n], 1] -> Stm[t, n]
      val suffix0 = expect(code, "SerializeN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (s, suffix7) = parseExpr(suffix6, modules)
      (StmJoin(StmMap(s, Missing ::+ (v => Vec2Stm(v)()))())(), suffix7)
    } else if (code.startsWith("DeserializeN ")) {
      // DeserializeN seems to have type
      //     Stm[t, n] -> Stm[Vec[t, n], 1]
      val suffix0 = expect(code, "DeserializeN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (_, suffix5) = parseTyp(suffix4)
      val suffix6 = expect(suffix5, " ")
      val (s, suffix7) = parseExpr(suffix6, modules)
      (Stm2Vec(s)(), suffix7)
    } else if (code.startsWith("Add_1_sN ")) {
      val suffix0 = expect(code, "Add_1_sN ")
      val (f, suffix1) = parseExpr(suffix0, modules)
      val suffix2 = expect(suffix1, " ")
      val (e, suffix3) = parseExpr(suffix2, modules)
      (VecBuild(1, U8 ::+ (_ => f(e)))(), suffix3)
    } else if (code.startsWith("Add_1_0_tN ")) {
      val suffix0 = expect(code, "Add_1_0_tN ")
      val (f, suffix1) = parseExpr(suffix0, modules)
      val suffix2 = expect(suffix1, " ")
      val (s, suffix3) = parseExpr(suffix2, modules)
      val g = makeUnaryFunction(f, modules)
      (StmMap(StmCst(1, s)(), g)(), suffix3)
    } else if (code.startsWith("Remove_1_sN ")) {
      // Remove_1_sN seems to have type
      //     (A -> B) -> SSeq 1 A -> B
      // Or, in the notation of this IR:
      //     (A -> B) -> Vec[A, 1] -> B
      val suffix0 = expect(code, "Remove_1_sN ")
      val (f, suffix1) = parseExpr(suffix0, modules)
      val suffix2 = expect(suffix1, " ")
      val (v, suffix3) = parseExpr(suffix2, modules)
      val g = makeUnaryFunction(f, modules)
      (g(VecAccess(v, 0)()), suffix3)
    } else if (code.startsWith("Remove_1_0_tN ")) {
      // NOTE: In theory, Remove_1_0_tN can be used to extract an integer from
      //       a stream, which is not allowed in the minimal IR.
      //       Here's why I don't handle that case.
      //
      // (1) Although one can technically directly write an Lst program that
      //     uses Remove_1_0_tN, there is no equivalent in Lseq and the
      //     Aetherling compiler never instantiates this primitive. Therefore,
      //     we should never actually encounter Remove_1_0_tN.
      // (2) It is still *possible* to handle programs like this by a sort of
      //     augmented streamification pass. This pass would need to move all
      //     Remove_1_t_tN expressions towards the root of the AST.
      //       (a) If you encounter an expression like
      //               5 + Remove_1_0_tN f s,
      //           rewrite it to Map_tN (x -> 5 + f x) s.
      //       (b) If you encounter an expression like
      //               Add_1_0_tN f (Remove_1_0_tN g s),
      //           rewrite it to Map_tN (f . g) s.
      //       (c) If Remove_1_0_tN reaches the root of the AST, just discard
      //           it.
      //
      // The claim that the minimalist IR is more expressive than Aetherling is
      // true, even if not every single Lst primitive is actually handled by
      // this parser.
      val suffix0 = expect(code, "Remove_1_0_tN ")
      val (f, suffix1) = parseExpr(suffix0, modules)
      val suffix2 = expect(suffix1, " ")
      val (s, suffix3) = parseExpr(suffix2, modules)
      val g = makeUnaryFunction(f, modules)
      (StmJoin(StmMap(s, g)())(), suffix3)
    } else if (code.startsWith("Map_sN ")) {
      val suffix0 = expect(code, "Map_sN ")
      // TODO: Assert type?
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (f, suffix3) = parseExpr(suffix2, modules)
      val suffix4 = expect(suffix3, " ")
      val (v, suffix5) = parseExpr(suffix4, modules)
      (VecMap(v, makeUnaryFunction(f, modules))(), suffix5)
    } else if (code.startsWith("Map_tN ")) {
      val suffix0 = expect(code, "Map_tN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (f, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (s, suffix7) = parseExpr(suffix6, modules)
      val g = makeUnaryFunction(f, modules)
      (StmMap(s, g)(), suffix7)
    } else if (code.startsWith("Map2_sN ")) {
      val suffix0 = expect(code, "Map2_sN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (f, suffix3) = parseExpr(suffix2, modules)
      val suffix4 = expect(suffix3, " ")
      val (v1, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (v2, suffix7) = parseExpr(suffix6, modules)
      (VecMap2(v1, v2, makeBinaryFunction(f, modules))(), suffix7)
    } else if (code.startsWith("Map2_tN ")) {
      val suffix0 = expect(code, "Map2_tN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (f, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (s1, suffix7) = parseExpr(suffix6, modules)
      val suffix8 = expect(suffix7, " ")
      val (s2, suffix9) = parseExpr(suffix8, modules)
      (StmMap2(s1, s2, makeBinaryFunction(f, modules))(), suffix9)
    } else if (code.startsWith("Reduce_sN ")) {
      val suffix0 = expect(code, "Reduce_sN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (f, suffix3) = parseExpr(suffix2, modules)
      val suffix4 = expect(suffix3, " ")
      val (v, suffix5) = parseExpr(suffix4, modules)
      (VecReduceComb(v, makeUnaryFunction(f, modules))(), suffix5)
    } else if (code.startsWith("Reduce_tN ")) {
      val suffix0 = expect(code, "Reduce_tN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (f, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (s, suffix7) = parseExpr(suffix6, modules)
      (StmReduce(s, makeUnaryFunction(f, modules))(), suffix7)
    } else if (code.startsWith("FstN ")) {
      val suffix0 = expect(code, "FstN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (e.__0, suffix5)
    } else if (code.startsWith("SndN ")) {
      val suffix0 = expect(code, "SndN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (e.__1, suffix5)
    } else if (code.startsWith("ATupleN ")) {
      val suffix0 = expect(code, "ATupleN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e0, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (e1, suffix7) = parseExpr(suffix6, modules)
      (Tuple(e0, e1)(), suffix7)
    } else if (code.startsWith("STupleN ")) {
      val suffix0 = expect(code, "STupleN ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (e0, suffix3) = parseExpr(suffix2, modules)
      val suffix4 = expect(suffix3, " ")
      val (e1, suffix5) = parseExpr(suffix4, modules)
      (VecBuild(2, U8 ::+ (i => Mux(i === 0, e0, e1)()))(), suffix5)
    } else if (code.startsWith("STupleAppendN ")) {
      val suffix0 = expect(code, "STupleAppendN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (tup, suffix5) = parseExpr(suffix4, modules)
      val suffix6 = expect(suffix5, " ")
      val (elem, suffix7) = parseExpr(suffix6, modules)
      (VecAppend(tup, elem)(), suffix7)
    } else if (code.startsWith("STupleToSSeqN ")) {
      val suffix0 = expect(code, "STupleToSSeqN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (e, suffix5)
    } else if (code.startsWith("SSeqToSTupleN ")) {
      val suffix0 = expect(code, "SSeqToSTupleN ")
      val (_, suffix1) = parseNat(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (e, suffix5)
    } else if (code.startsWith("FIFON ")) {
      val suffix0 = expect(code, "FIFON ")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, " ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, " ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (Fifo(e), suffix5)
    } else if (code.startsWith("ReshapeN (")) {
      val suffix0 = expect(code, "ReshapeN (")
      val (_, suffix1) = parseTyp(suffix0)
      val suffix2 = expect(suffix1, ") (")
      val (targetTyp, suffix3) = parseTyp(suffix2)
      val suffix4 = expect(suffix3, ") ")
      val (e, suffix5) = parseExpr(suffix4, modules)
      (ReshapeSeq(e, targetTyp)(), suffix5)
    } else if (code.startsWith("\"")) {
      parseQuotedIdentifier(code)
    } else if (code.head.isLetter) {
      parseIdentifier(code)
    } else {
      throw SyntaxError(s"Expected an expression but got $code")
    }
  }

  /** Turn an Aetherling expression that stands in for a function into a proper
    * function.
    *
    * In Aetherling, functions can sometimes be implicit. For example, you would
    * write `map_s (add I) my_seq` rather than `map_s (I => add I) my_seq`. `I`
    * is implicitly understood to be the parameter of the function. But you
    * could also write `map_s module0 I` where `module0` is a previously-defined
    * function, in which case `module0` is already a function.
    */
  private def makeUnaryFunction(
      e: Expr,
      modules: Map[Param, Function]
  ): Expr = {
    e match {
      case f: Param if modules.contains(f) =>
        f
      case body =>
        Function(Param("I", -1)(Missing), body)()
    }
  }

  private def makeBinaryFunction(
      f: Expr,
      modules: Map[Param, Function]
  ): Expr = {
    f match {
      case x: Param if modules.contains(x) =>
        x
      case _ =>
        Function(
          Param("I0", -1)(Missing),
          Function(Param("I1", -1)(Missing), f)()
        )()
    }
  }

  private def makeNestedStmShift(
      s: Expr,
      nis: Seq[Int],
      iis: Seq[Int],
      shiftAmount: Int
  ): Expr = {
    (nis, iis) match {
      case (Seq(), Seq()) =>
        StmShiftRightGarbage(s, shiftAmount)()
      case (ni +: nis, _ +: iis) =>
        StmSplit(makeNestedStmShift(StmJoin(s)(), nis, iis, shiftAmount), ni)()
      case (_, _) =>
        throw SyntaxError(
          s"Length mismatch in shift_tn: $nis vs $iis."
        )
    }
  }

  private def makeNestedStmCounter(
      nProd: Int,
      ns: Seq[Int],
      is: Seq[Int],
      delta: Int,
      typ: Type
  ): Expr = {
    (ns, is) match {
      case (Seq(_), Seq(_)) =>
        StmRange(nProd, C(0)(typ), C(delta)(typ))()
      case (n +: ns, _ +: is) =>
        val innerCount = makeNestedStmCounter(nProd * n, ns, is, delta, typ)
        StmSplit(innerCount, n)()
      case _ =>
        throw SyntaxError(s"Length mismatch in counter_tn: $ns vs $is.")
    }
  }

  private def parseConst(code: String): (Expr, String) = {
    if (code.startsWith("UnitV")) {
      val suffix0 = expect(code, "UnitV")
      (Tuple()(), suffix0)
    } else if (code.startsWith("BitV False")) {
      (False, expect(code, "BitV False"))
    } else if (code.startsWith("BitV True")) {
      (True, expect(code, "BitV True"))
    } else if (code.startsWith("Int8V ")) {
      val suffix0 = expect(code, "Int8V ")
      val (n, suffix1) = parseInt(suffix0)
      (C(n)(I8), suffix1)
    } else if (code.startsWith("UInt8V ")) {
      val suffix0 = expect(code, "UInt8V ")
      val (n, suffix1) = parseNat(suffix0)
      (C(n)(U8), suffix1)
    } else if (code.startsWith("FixP1_7V ")) {
      val suffix0 = expect(code, "FixP1_7V ")
      val (float, suffix1) = parseFloat(suffix0)
      val c = FixCst((float * 128).round)(TyFix(U8, 7))
      (c, suffix1)
    } else if (code.startsWith("Int16V ")) {
      val suffix0 = expect(code, "Int16V ")
      val (n, suffix1) = parseInt(suffix0)
      (C(n)(I16), suffix1)
    } else if (code.startsWith("UInt16V ")) {
      val suffix0 = expect(code, "UInt16V ")
      val (n, suffix1) = parseNat(suffix0)
      (C(n)(U16), suffix1)
    } else if (code.startsWith("Int32V ")) {
      val suffix0 = expect(code, "Int32V ")
      val (n, suffix1) = parseInt(suffix0)
      (C(n)(I32), suffix1)
    } else if (code.startsWith("UInt32V ")) {
      val suffix0 = expect(code, "UInt32V ")
      val (n, suffix1) = parseNat(suffix0)
      (C(n)(U32), suffix1)
    } else if (code.startsWith("ATupleV ")) {
      val suffix0 = expect(code, "ATupleV (")
      val (v0, suffix1) = parseConst(suffix0)
      val suffix2 = expect(suffix1, ") (")
      val (v1, suffix3) = parseConst(suffix2)
      val suffix4 = expect(suffix3, ")")
      (Tuple(v0, v1)(), suffix4)
    } else if (code.startsWith("STupleV ")) {
      val suffix0 = expect(code, "STupleV ")
      val (elems, suffix1) = parseConstList(suffix0)
      (VecLiteral(elems: _*)(), suffix1)
    } else if (code.startsWith("SSeqV ")) {
      val suffix0 = expect(code, "SSeqV ")
      val (elems, suffix1) = parseConstList(suffix0)
      (VecLiteral(elems: _*)(), suffix1)
    } else if (code.startsWith("TSeqV {vals = ")) {
      val suffix0 = expect(code, "TSeqV {vals = ")
      val (elems, suffix1) = parseConstList(suffix0)
      val suffix2 = expect(suffix1, ", i_v = ")
      val (_, suffix3) = parseNat(suffix2)
      val suffix4 = expect(suffix3, "}")
      (StmLiteral(elems: _*)(), suffix4)
    } else {
      throw SyntaxError(s"Expected a constant but got $code")
    }
  }

  private def parseConstList(code: String): (Seq[Expr], String) = {
    if (code.startsWith("[]")) {
      (Seq(), expect(code, "[]"))
    } else {
      val suffix0 = expect(code, "[")
      val (elems, suffix1) = parseOneOrMoreConst(suffix0, Seq())
      val suffix2 = expect(suffix1, "]")
      (elems, suffix2)
    }
  }

  @tailrec
  private def parseOneOrMoreConst(
      code: String,
      elems: Seq[Expr]
  ): (Seq[Expr], String) = {
    val (elem0, suffix0) = parseConst(code)
    if (suffix0.startsWith(",")) {
      val suffix1 = expect(suffix0, ",")
      parseOneOrMoreConst(suffix1, elems :+ elem0)
    } else {
      (elems :+ elem0, suffix0)
    }
  }

  private def expect(code: String, prefix: String): String = {
    if (!code.startsWith(prefix)) {
      throw SyntaxError(s"Expected '$prefix' but got $code")
    }
    code.substring(prefix.length)
  }
}
